(17, 1, 'Accra Senior High School', 'Excellence Through Knowledge', 'A leading Senior High School in Accra, Ghana, committed to academic excellence and holistic development.', 'To be the premier institution for secondary education in Ghana, producing well-rounded graduates.', 'To provide quality education that empowers students to excel academically and contribute positively to society.', '/uploads/institutions/accra-shs/logo.png', NULL, '#006B3F', '#FCD116', 'Africa/Accra', 9, 6, 'ghana_waec', 'en_GH', 'GHS', 'Y-m-d', 'H:i:s', 1, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-03 21:21:31'),
(18, 2, 'Kumasi Senior High School', 'Knowledge is Power', 'Premier institution in the Ashanti Region dedicated to nurturing future leaders.', 'To be recognized as a center of excellence in secondary education across West Africa.', 'Empowering students with knowledge, skills, and character for global competitiveness.', '/uploads/institutions/kumasi-shs/logo.png', NULL, '#C8102E', '#FCD116', 'Africa/Accra', 9, 6, 'ghana_waec', 'en_GH', 'GHS', 'Y-m-d', 'H:i:s', 1, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-03 21:21:31'),
(20, 4, 'Tamale Senior High School', 'Service and Dedication', 'Leading the way in quality education in Northern Ghana.', 'To be the educational beacon of Northern Ghana, inspiring excellence.', 'Providing comprehensive education that prepares students for leadership and service.', '/uploads/institutions/tamale-shs/logo.png', NULL, '#228B22', '#FFD700', 'Africa/Accra', 9, 6, 'ghana_waec', 'en_GH', 'GHS', 'Y-m-d', 'H:i:s', 1, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-03 21:21:31'),
(21, 5, 'Ho Senior High School', 'Unity and Progress', 'Excellence in education for the Volta Region and beyond.', 'To cultivate a community of learners committed to excellence and innovation.', 'Nurturing talents and building character for national development.', '/uploads/institutions/ho-shs/logo.png', NULL, '#006400', '#FFFFFF', 'Africa/Accra', 9, 6, 'ghana_waec', 'en_GH', 'GHS', 'Y-m-d', 'H:i:s', 1, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-03 21:21:31'),
